//===- LLVMIROptimizeFloorDiv.cpp - Optimize XOR floor division pattern ---===//
//
// This pass transforms the XOR-based floor division pattern (generated by
// PyTorch's inductor to work around a Triton AxisInfo bug) back into the
// efficient sdiv+srem pattern. The AxisInfo analysis runs during the MLIR
// phase, so this LLVM IR transformation is safe.
//
// The XOR pattern:
//   %cmp    = icmp slt %x, 0
//   %not_x  = xor %x, -1
//   %abs_x  = select %cmp, %not_x, %x
//   %quot   = sdiv %abs_x, <const_d>
//   %not_q  = xor %quot, -1
//   %result = select %cmp, %not_q, %quot
//
// Is replaced with:
//   %quot    = sdiv %x, <const_d>
//   %rem     = srem %x, <const_d>
//   %is_neg  = icmp slt %x, 0
//   %has_rem = icmp ne %rem, 0
//   %adj     = and %is_neg, %has_rem
//   %dec     = add %quot, -1
//   %result  = select %adj, %dec, %quot
//
// Both compute floordiv(x, d). The sdiv+srem form allows LLVM's GVN to share
// the division result across warp lanes, producing the same efficient LLIR
// that IGC optimizes well.
//
//===----------------------------------------------------------------------===//

#include "LLVMPasses.h"
#include "llvm/IR/Constants.h"
#include "llvm/IR/IRBuilder.h"
#include "llvm/IR/Instructions.h"

using namespace llvm;

static bool isConstantMinusOne(Value *V) {
  if (auto *CI = dyn_cast<ConstantInt>(V))
    return CI->isMinusOne();
  return false;
}

static bool isConstantZero(Value *V) {
  if (auto *CI = dyn_cast<ConstantInt>(V))
    return CI->isZero();
  return false;
}

static bool runOnFunction(Function &F) {
  bool Changed = false;
  SmallVector<Instruction *, 8> ToErase;

  for (auto &BB : F) {
    for (auto &I : BB) {
      // Match root: %result = select %cmp, %not_q, %quot
      auto *OuterSel = dyn_cast<SelectInst>(&I);
      if (!OuterSel)
        continue;

      Value *Cond = OuterSel->getCondition();
      Value *TrueVal = OuterSel->getTrueValue();
      Value *FalseVal = OuterSel->getFalseValue();

      // %not_q = xor %quot, -1
      auto *NotQuot = dyn_cast<BinaryOperator>(TrueVal);
      if (!NotQuot || NotQuot->getOpcode() != Instruction::Xor)
        continue;

      Value *QuotVal = nullptr;
      if (isConstantMinusOne(NotQuot->getOperand(1)))
        QuotVal = NotQuot->getOperand(0);
      else if (isConstantMinusOne(NotQuot->getOperand(0)))
        QuotVal = NotQuot->getOperand(1);
      else
        continue;

      // FalseVal must be the same %quot
      if (FalseVal != QuotVal)
        continue;

      // %quot = sdiv %abs_x, <const_d>
      auto *Div = dyn_cast<BinaryOperator>(QuotVal);
      if (!Div || Div->getOpcode() != Instruction::SDiv)
        continue;

      Value *AbsX = Div->getOperand(0);
      auto *ConstD = dyn_cast<ConstantInt>(Div->getOperand(1));
      if (!ConstD || ConstD->isNegative() || ConstD->isZero())
        continue;

      // %abs_x = select %cmp, %not_x, %x  (same condition)
      auto *InnerSel = dyn_cast<SelectInst>(AbsX);
      if (!InnerSel || InnerSel->getCondition() != Cond)
        continue;

      Value *NotX = InnerSel->getTrueValue();
      Value *X = InnerSel->getFalseValue();

      // %not_x = xor %x, -1
      auto *NotXOp = dyn_cast<BinaryOperator>(NotX);
      if (!NotXOp || NotXOp->getOpcode() != Instruction::Xor)
        continue;
      if (!((NotXOp->getOperand(0) == X &&
             isConstantMinusOne(NotXOp->getOperand(1))) ||
            (NotXOp->getOperand(1) == X &&
             isConstantMinusOne(NotXOp->getOperand(0)))))
        continue;

      // %cmp = icmp slt ?, 0
      // The condition may be shared across warp lanes (LLVM CSE'd the icmp
      // when all lanes have the same sign). We only require icmp slt with 0,
      // not that the icmp operand is exactly X.
      auto *Cmp = dyn_cast<ICmpInst>(Cond);
      if (!Cmp || Cmp->getPredicate() != ICmpInst::ICMP_SLT)
        continue;
      if (!isConstantZero(Cmp->getOperand(1)))
        continue;

      // Full pattern matched! Replace with sdiv+srem floor division.
      IRBuilder<> Builder(OuterSel);
      Value *Quot = Builder.CreateSDiv(X, ConstD, "floordiv.quot");
      Value *Rem = Builder.CreateSRem(X, ConstD, "floordiv.rem");
      Value *IsNeg = Builder.CreateICmpSLT(X, ConstantInt::get(X->getType(), 0),
                                           "floordiv.neg");
      Value *HasRem = Builder.CreateICmpNE(
          Rem, ConstantInt::get(Rem->getType(), 0), "floordiv.hasrem");
      Value *NeedAdj = Builder.CreateAnd(IsNeg, HasRem, "floordiv.adj");
      Value *Dec = Builder.CreateAdd(
          Quot, ConstantInt::getSigned(Quot->getType(), -1), "floordiv.dec");
      Value *Result = Builder.CreateSelect(NeedAdj, Dec, Quot, "floordiv");

      OuterSel->replaceAllUsesWith(Result);
      ToErase.push_back(OuterSel);
      Changed = true;
    }
  }

  for (auto *I : ToErase)
    I->eraseFromParent();
  return Changed;
}

PreservedAnalyses OptimizeFloorDivPass::run(Function &F,
                                            FunctionAnalysisManager &FAM) {
  return runOnFunction(F) ? PreservedAnalyses::none()
                          : PreservedAnalyses::all();
}
